php echo e($fuelType); ?>"><?php echo e($fuelType); ?></option><?php endforeach; ?></select><select class="form-select" id="fuelShiftFilter"><option value="">All shifts</option><?php foreach ($shifts as $shift): ?><option value="<?php echo e($shift); ?>"><?php echo e($shift); ?></option><?php endforeach; ?></select><select class="form-select" id="fuelPumpFilter"><option value="">All pumps</option><?php foreach ($pumps as $pump): ?><option value="<?php echo e($pump); ?>"><?php echo e($pump); ?></option><?php endforeach; ?></select><select class="form-select" id="fuelStatusFilter"><option value="">All statuses</option><?php foreach ($salesStatuses as $status): ?><option value="<?php echo e($status); ?>"><?php echo e($status); ?></option><?php endforeach; ?></select></div><div class="table-responsive"><table class="table attendance-table fuel-table align-middle"><thead><tr><th>Date</th><th>Transaction ID</th><th>Pump</th><th>Fuel Type</th><th>Shift</th><th>Attendant</th><th>Liters Sold</th><th>Amount</th><th>Status</th></tr></thead><tbody><?php foreach ($fuelSales as $sale): ?><tr data-fuel-row data-search="<?php echo e(strtolower($sale['transaction_id'] . ' ' . $sale['attendant'] . ' ' . $sale['pump'])); ?>" data-date="<?php echo e($sale['date']); ?>" data-shift="<?php echo e($sale['shift']); ?>" data-pump="<?php echo e($sale['pump']); ?>" data-fuel="<?php echo e($sale['fuel_type']); ?>" data-status="<?php echo e($sale['status']); ?>" data-attendant="<?php echo e($sale['attendant']); ?>"><td><?php echo e(format_date($sale['date'])); ?></td><td><strong><?php echo e($sale['transaction_id']); ?></strong></td><td><?php echo e($sale['pump']); ?></td><td><?php echo e($sale['fuel_type']); ?></td><td><?php echo e($sale['shift']); ?></td><td><?php echo e($sale['attendant']); ?></td><td><?php echo e(number_format($sale['liters_sold'])); ?> L</td><td>NGN <?php echo e(number_format($sale['amount'])); ?></td><td><span class="table-badge <?php echo e($salesStatusClasses[$sale['status']]); ?>"><?php echo e($sale['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="fuel-pagination"><span id="fuelPageSummary">Showing fuel sales records</span><div><button class="btn btn-outline-brand btn-sm" id="prevFuelPage" type="button"><i class="fa-solid fa-chevron-left"></i></button><button class="btn btn-outline-brand btn-sm" id="nextFuelPage" type="button"><i class="fa-solid fa-chevron-right"></i></button></div></div></article></section></main><?php require __DIR__ . '/../includes/footer.php'; ?>



